// app/page.tsx — full chat UI in ~15 lines
"use client";
import { useEdgeRuntime }           from "@assistant-ui/react";
import { AssistantRuntimeProvider,
         Thread }                   from "@assistant-ui/react";

export default function ChatPage() {
  // useEdgeRuntime: sends messages to /api/chat and reads the AI SDK stream
  const runtime = useEdgeRuntime({ url: "/api/chat" });

  return (
    <AssistantRuntimeProvider runtime={runtime}>
      <div className="flex h-screen flex-col bg-slate-950">
        {/* Thread renders the full chat: message list + composer */}
        <Thread />
      </div>
    </AssistantRuntimeProvider>
  );
}

// app/api/chat/route.ts — Next.js Edge Route (AI SDK + Anthropic)
import { anthropic }          from "@ai-sdk/anthropic";
import { streamText }         from "ai";
import { toDataStreamResponse } from "@assistant-ui/react/edge";
import type { NextRequest }   from "next/server";

export const runtime = "edge";

export async function POST(req: NextRequest) {
  const { messages, system, tools } = await req.json();

  const result = streamText({
    model:   anthropic("claude-opus-4-8"),
    system:  system ?? "You are a helpful assistant.",
    messages,
    tools,
  });

  // toDataStreamResponse converts AI SDK stream to the format
  // that useEdgeRuntime / useLocalRuntime expect
  return result.toDataStreamResponse();
}

// CustomThread.tsx — build a bespoke UI using headless primitives
import {
  Thread, ThreadMessages, Composer,
  ComposerInput, ComposerSend,
  AssistantMessage, UserMessage,
} from "@assistant-ui/react";

export function CustomThread() {
  return (
    <Thread.Root className="flex h-full flex-col bg-slate-950 text-slate-100">
      {/* Scrollable message list */}
      <Thread.Viewport className="flex-1 overflow-y-auto px-4 py-6 space-y-4">
        <Thread.Messages
          components={{
            UserMessage:      CustomUserMessage,
            AssistantMessage: CustomAssistantMessage,
          }}
        />
      </Thread.Viewport>

      {/* Input area */}
      <Thread.ScrollToBottom className="mx-auto mb-2 text-xs text-slate-500 hover:text-slate-300 cursor-pointer" />
      <Composer.Root className="mx-4 mb-4 flex items-end gap-2 rounded-2xl border border-slate-700 bg-slate-900 px-3 py-2">
        <Composer.Input
          className="flex-1 resize-none bg-transparent text-sm outline-none placeholder:text-slate-500"
          placeholder="Message..."
          rows={1}
        />
        <Composer.Send className="shrink-0 rounded-lg bg-indigo-600 px-3 py-1.5 text-sm text-white
                                  hover:bg-indigo-500 disabled:opacity-40">
          Send
        </Composer.Send>
      </Composer.Root>
    </Thread.Root>
  );
}

function CustomUserMessage() {
  return (
    <UserMessage.Root className="flex justify-end">
      <UserMessage.Content className="max-w-[75%] rounded-2xl bg-indigo-700 px-4 py-2 text-sm text-white" />
    </UserMessage.Root>
  );
}

function CustomAssistantMessage() {
  return (
    <AssistantMessage.Root className="flex gap-3">
      <div className="mt-1 h-7 w-7 shrink-0 rounded-full bg-indigo-900 grid place-items-center text-indigo-300 text-xs">AI</div>
      <AssistantMessage.Content className="text-sm text-slate-200 leading-relaxed" />
    </AssistantMessage.Root>
  );
}

// Register a tool renderer — shown inline when the model calls that tool
import { makeAssistantTool } from "@assistant-ui/react";
import { z }                 from "zod";

// Define the tool schema (mirrors the tool definition sent to the model)
export const FlightSearchTool = makeAssistantTool({
  toolName: "search_flights",
  // Zod schema for the tool's args:
  parameters: z.object({
    origin:      z.string(),
    destination: z.string(),
    date:        z.string(),
    flights:     z.array(z.object({
      id:       z.string(),
      airline:  z.string(),
      price:    z.number(),
      departs:  z.string(),
    })).optional(),
  }),
  // render is called while args stream in (argsText is partial JSON)
  // and again after the tool result returns
  render: function FlightSearchRender({ args, result, status }) {
    if (status.type === "running") {
      return (
        <div className="my-2 rounded-xl border border-slate-700 p-3 text-sm text-slate-400 animate-pulse">
          Searching flights from {args.origin ?? "..."} to {args.destination ?? "..."}...
        </div>
      );
    }

    const flights = args.flights ?? (result as any)?.flights ?? [];
    return (
      <div className="my-2 rounded-xl border border-slate-700 overflow-hidden">
        <p className="px-4 py-2 text-xs text-slate-400 bg-slate-900 border-b border-slate-800">
          {flights.length} flights found
        </p>
        {flights.map((f: any) => (
          <div key={f.id} className="flex items-center gap-4 px-4 py-2 border-b border-slate-800 hover:bg-slate-800/50">
            <span className="text-slate-200 text-sm flex-1">{f.airline}  {f.departs}</span>
            <span className="text-indigo-300 font-bold">${f.price}</span>
            <button className="text-xs bg-indigo-600 hover:bg-indigo-500 text-white px-3 py-1 rounded-lg">Book</button>
          </div>
        ))}
      </div>
    );
  },
});

// In the Thread, register the tool renderer:
// <Thread tools={[FlightSearchTool]} />

// Reading thread state with hooks
import { useThread, useMessage, useComposer } from "@assistant-ui/react";

function ThreadStatus() {
  const thread = useThread();
  return (
    <div className="text-xs text-slate-500 px-4 py-1">
      {thread.isRunning ? "Thinking..." : `${thread.messages.length} messages`}
    </div>
  );
}

function MessageActions() {
  const message = useMessage();   // available inside Thread.Messages context
  return (
    <div className="opacity-0 group-hover:opacity-100 flex gap-1 mt-1">
      <button onClick={() => navigator.clipboard.writeText(message.content[0]?.type === "text" ? message.content[0].text : "")}
              className="text-xs text-slate-500 hover:text-slate-300">
        Copy
      </button>
    </div>
  );
}

// Programmatic thread control
function ExternalControls() {
  const thread = useThread();
  return (
    <button onClick={() => thread.composer.setInput("Summarise the conversation")}
            className="text-xs text-slate-400 hover:text-slate-200">
      Auto-fill prompt
    </button>
  );
}

// Chat component tests
import { render, screen } from "@testing-library/react";
import userEvent           from "@testing-library/user-event";
import { AssistantRuntimeProvider } from "@assistant-ui/react";
import { createLocalRuntime }       from "@assistant-ui/react";
import { CustomThread }             from "./CustomThread";

// createLocalRuntime lets you run tests without a real backend
function createTestRuntime() {
  return createLocalRuntime({
    onNew: async (message, { sendText }) => {
      // Simple echo for tests
      await sendText(`Echo: ${message.content[0].type === "text" ? message.content[0].text : ""}`);
    },
  });
}

test("sends message and shows response", async () => {
  const user    = userEvent.setup();
  const runtime = createTestRuntime();

  render(
    <AssistantRuntimeProvider runtime={runtime}>
      <CustomThread />
    </AssistantRuntimeProvider>
  );

  await user.type(screen.getByPlaceholderText("Message..."), "Hello");
  await user.click(screen.getByRole("button", { name: /send/i }));

  expect(await screen.findByText(/Echo: Hello/i)).toBeInTheDocument();
});
